#include<stdio.h>

int isLeap(year)
{
	if(year%4==0 && year%100!=0 || year%400==0)
		return 29;
	else
		return 28;
}

int no_of_days_remaining(int mon,int year)
{
	int days=0;
	switch(mon)
		{
			case 1:days+=31;
			case 2:days+=isLeap(year);
			case 3:days+=31;
			case 4:days+=30;
			case 5:days+=31;
			case 6:days+=30;
			case 7:days+=31;
			case 8:days+=31;
			case 9:days+=30;
			case 10:days+=31;
			case 11:days+=30;
			case 12:days+=31;
		}
	return days;
}

int no_of_days_passed(int mon, int year)
	{
		int days=0;
		switch(mon)
			{
			case 12:days+=31;
			case 11:days+=30;
			case 10:days+=31;
			case 9:days+=30;
			case 8:days+=31;
			case 7:days+=31;
			case 6:days+=30;
			case 5:days+=31;
			case 4:days+=30;
			case 3:days+=31;
			case 2:days+=isLeap(year);
			case 1:days+=31;
			}
		return days;
	}

int no_of_days(int year)
{
	int k=31*7+30*4+isLeap(year);
	return k;
}

